export default new Vuex.Store({
  state: {
    status: {
      loggedIn: false,
      userId: -1,
      username: "",
      userType: 0,
      permission: 0
    },
    sideBarItems: [],
    loading: false
  },

mutations: {
    SET_LOGIN_STATUS(state, payload) {
      state.status.loggedIn = payload;
    },
    SET_USER_ID(state, payload) {
      state.status.userId = payload;
    },
    SET_USERNAME(state, payload) {
      state.status.username = payload;
    },
    SET_USER_TYPE(state, payload) {
      state.status.userType = payload;
    },
    SET_PERMISSION(state, payload) {
      state.status.permission = payload;
    },
    SET_SIDEBAR_ITEMS(state, payload) {
      state.sideBarItems = payload;
    },
    SET_LOADING(state, payload) {
      state.loading = payload;
    }
  },
  actions: {
    setLoginStatus({ commit }, payload) {
      commit("SET_LOGIN_STATUS", payload);
    },
    setUserId({ commit }, payload) {
      commit("SET_USER_ID", payload);
    },
    setUsername({ commit }, payload) {
      commit("SET_USERNAME", payload);
    },
    setUserType({ commit }, payload) {
      commit("SET_USER_TYPE", payload);
    },
    setPermission({ commit }, payload) {
      commit("SET_PERMISSION", payload);
    },
    setSideBarItems({ commit }, payload) {
      commit("SET_SIDEBAR_ITEMS", payload);
    },
    setLoading({ commit }, payload) {
      commit("SET_LOADING", payload);
    }
  },
  getters: {
    isLoggedIn: state => state.status.loggedIn,
    getUserId: state => state.status.userId,
    getUsername: state => state.status.username,
    getUserType: state => state.status.userType,
    getPermission: state => state.status.permission,
    getSideBarItems: state => state.sideBarItems,
    isLoading: state => state.loading
  }
});

